code.C:
#include <stdio.h>
int main() {
    int jacketCost, sockCost, money;
    scanf("%d %d %d", &jacketCost, &sockCost, &money);
    int remainingMoney = money - jacketCost;
    int numSocks = remainingMoney / sockCost;
    if (numSocks % 2 == 1) {
        printf("Unlucky Chef\n");
    } else {
        printf("Lucky Chef\n");
    }
    return 0;
}

